    }
  },
  "get_vehicle_telemetry": {
    "description": "Provides real-time data for a specific vehicle, including its delay in seconds (positive for late, negative for early) and current stop information.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The unique identifier for the vehicle (e.g., 'V-402-9')."
