    "description": "Determines if a vehicle is positioned north or south of a specific landmark to ensure compliance with operational restrictions.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The ID of the vehicle to check."
        },
        "landmark": {
