    }
  },
  "apply_recovery_directive": {
    "description": "Issues operational directives to adjust the schedule of a vehicle. This action updates the 'delay_seconds' attribute in the environment state to reflect the impact of the directive.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The ID of the vehicle."
        },
        "strategy": {
          "type": "string",
          "enum": [
            "skip_stops",
            "express_to_terminal",
            "deadhead",
            "hold_at_stop",
            "increase_dwell_time"
          ],
          "description": "The strategy to mitigate delay or early arrival. Use 'hold_at_stop' or 'increase_dwell_time' for early arrivals."
        },
        "target_value": {
          "type": "string",
          "description": "The target arrival time or the duration for the hold (e.g., '09:30:00' or '120s')."
        }
      },
      "required": [
        "vehicle_id",
        "strategy",
        "target_value"
      ]
    },
